1	export type Scenario = {
2	  customer: { yearsWithMHPCO: number };
3	  steps: any[];
4	};
5	
6	export type ScenarioResult = {
7	  results: any[];
8	};
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE = 0.1;
12	const CURSE_SURCHARGE = 0.5;
13	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
14	const HIGH_ENCHANTMENT_THRESHOLD = 5;
15	const LOYALTY_DISCOUNT = 0.2;
16	const LOYALTY_YEARS_THRESHOLD = 2;
17	const FOLLOWUP_DISCOUNT = 0.15;
18	const CLAIM_DEDUCTIBLE = 100;
19	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
20	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
21	const COMPONENT_BLOCK_SIZE = 3;
22	const COMPONENT_BLOCK_PREMIUM = 60;
23	
24	const BASE_PREMIUM: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	
35	const roundUp = (value: number) => Math.ceil(Math.round(value * 1e6) / 1e6);
36	
37	const componentBasePremium = (count: number, perUnit: number) => {
38	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
39	  return count * perUnit;
40	};
41	
42	type PremiumEntry = { base: number; surchargePct: number };
43	
44	const itemSurchargePct = (item: any): number =>
45	  FIRST_INSURANCE_SURCHARGE +
46	  (item.cursed ? CURSE_SURCHARGE : 0) +
47	  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
48	    ? HIGH_ENCHANTMENT_SURCHARGE
49	    : 0);
50	
51	const singleItemEntry = (item: any): PremiumEntry => ({
52	  base: BASE_PREMIUM[item.type],
53	  surchargePct: itemSurchargePct(item),
54	});
55	
56	const componentGroupEntry = (type: string, count: number): PremiumEntry => ({
57	  base: componentBasePremium(count, BASE_PREMIUM[type]),
58	  surchargePct: FIRST_INSURANCE_SURCHARGE,
59	});
60	
61	const assertKnownItemTypes = (items: any[]): void => {
62	  const unknown = items.find((item) => !(item.type in BASE_PREMIUM));
63	  if (unknown) {
64	    throw new Error(`unknown item type: ${unknown.type}`);
65	  }
66	};
67	
68	const premiumEntries = (items: any[]): PremiumEntry[] => {
69	  assertKnownItemTypes(items);
70	  const singles = items
71	    .filter((item) => !COMPONENT_TYPES.has(item.type))
72	    .map(singleItemEntry);
73	  const componentCounts = items
74	    .filter((item) => COMPONENT_TYPES.has(item.type))
75	    .reduce<Record<string, number>>(
76	      (counts, item) => ({ ...counts, [item.type]: (counts[item.type] ?? 0) + 1 }),
77	      {},
78	    );
79	  const componentGroups = Object.entries(componentCounts).map(
80	    ([type, count]) => componentGroupEntry(type, count),
81	  );
82	  return [...singles, ...componentGroups];
83	};
84	
85	const policyModifierPct = (
86	  customer: Scenario["customer"],
87	  isFollowUp: boolean,
88	): number => {
89	  const loyalty =
90	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 0;
91	  const followUp = isFollowUp ? FOLLOWUP_DISCOUNT : 0;
92	  return -(loyalty + followUp);
93	};
94	
95	const quote = (
96	  step: any,
97	  customer: Scenario["customer"],
98	  isFollowUp: boolean,
99	) => {
100	  const policyPct = policyModifierPct(customer, isFollowUp);
101	  const total = premiumEntries(step.items).reduce(
102	    (sum, { base, surchargePct }) => sum + base * (1 + surchargePct + policyPct),
103	    PROCESSING_FEE,
104	  );
105	  return { premium: roundUp(total) };
106	};
107	
108	const previousQuoteCount = (steps: any[], index: number): number =>
109	  steps.slice(0, index).filter((step) => step.op === "quote").length;
110	
111	const isHighEnchantmentClaim = (item: any): boolean =>
112	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
113	
114	const reimbursableAmount = (amount: number, item: any): number =>
115	  isHighEnchantmentClaim(item) ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE : amount;
116	
117	const damagePayout = (amount: number, item: any): number =>
118	  Math.max(0, reimbursableAmount(amount, item) - CLAIM_DEDUCTIBLE);
119	
120	const findPolicyItem = (policyItems: any[], itemType: string): any => {
121	  const item = policyItems.find((it) => it.type === itemType);
122	  if (!item) {
123	    throw new Error(`damage references item not in policy: ${itemType}`);
124	  }
125	  return item;
126	};
127	
128	const assertNonNegativeDamage = (damage: any): void => {
129	  if (damage.amount < 0) {
130	    throw new Error(`negative damage amount: ${damage.amount}`);
131	  }
132	};
133	
134	const damageEntryPayout = (damage: any, policyItems: any[]): number => {
135	  assertNonNegativeDamage(damage);
136	  return damagePayout(damage.amount, findPolicyItem(policyItems, damage.itemType));
137	};
138	
139	const countsByType = (entries: any[], typeKey: string): Record<string, number> =>
140	  entries.reduce<Record<string, number>>(
141	    (counts, entry) => ({ ...counts, [entry[typeKey]]: (counts[entry[typeKey]] ?? 0) + 1 }),
142	    {},
143	  );
144	
145	const assertDamageCountsWithinPolicy = (damages: any[], policyItems: any[]): void => {
146	  const insured = countsByType(policyItems, "type");
147	  const damaged = countsByType(damages, "itemType");
148	  for (const [type, count] of Object.entries(damaged)) {
149	    const covered = insured[type] ?? 0;
150	    if (covered > 0 && count > covered) {
151	      throw new Error(`more damage entries for ${type} than policy covers`);
152	    }
153	  }
154	};
155	
156	const claim = (step: any, policyItems: any[]): { payout: number } => {
157	  assertDamageCountsWithinPolicy(step.incident.damages, policyItems);
158	  const total = step.incident.damages.reduce(
159	    (sum: number, damage: any) => sum + damageEntryPayout(damage, policyItems),
160	    0,
161	  );
162	  return { payout: Math.floor(total) };
163	};
164	
165	export const runScenario = (scenario: Scenario): ScenarioResult => {
166	  const results = scenario.steps.map((step, index) => {
167	    if (step.op === "quote") {
168	      const isFollowUp = previousQuoteCount(scenario.steps, index) > 0;
169	      return quote(step, scenario.customer, isFollowUp);
170	    }
171	    if (step.op === "claim") {
172	      const policyStep = scenario.steps[step.policy];
173	      return claim(step, policyStep.items);
174	    }
175	    return {};
176	  });
177	  return { results };
178	};
